const chalk = require('chalk');
const { Installer } = require('../lib/installer');
const { UI } = require('../lib/ui');

module.exports = {
  command: 'install',
  description: 'Install SKF agents and workflows into your project',
  options: [],
  action: async () => {
    try {
      const ui = new UI();
      const config = await ui.promptInstall();

      if (config.cancelled) {
        console.log(chalk.yellow('\nInstallation cancelled.'));
        process.exit(0);
        return;
      }

      const installer = new Installer();
      const result = await installer.install(config);

      if (result && result.success) {
        ui.displaySuccess(config.skfFolder, config.ides, config._action);
        process.exit(0);
      }
    } catch (error) {
      console.error(chalk.red('\nInstallation failed:'), error.message);
      console.error(chalk.dim(error.stack));
      process.exit(1);
    }
  },
};

/**
 * SKF Installer UI - Banner, prompts, and success message.
 * Uses @clack/prompts for terminal UI.
 *
 * Brand palette (from skf-logo.svg):
 *   amber  #F59E0B  — primary (anvil top)
 *   gold   #FBBF24  — accent, highlights (anvil horn)
 *   dark   #D97706  — frame, deep emphasis (anvil body)
 *   spark  #FCD34D  — sparks, icons
 */

const { intro, outro, text, select, multiselect, confirm, note, isCancel, cancel, log } = require('@clack/prompts');
const chalk = require('chalk');
const figlet = require('figlet');
const path = require('node:path');
const fs = require('fs-extra');
const yaml = require('js-yaml');
const { readManifest } = require('./manifest');
const { compareVersions } = require('./version-check');
const { getAvailablePlatforms, getDetectionMarkers } = require('./ide-skills');

const SKF_FOLDER = '_bmad/skf';

// Brand colors derived from skf-logo.svg
const brand = {
  amber: chalk.hex('#F59E0B'),
  gold: chalk.hex('#FBBF24'),
  dark: chalk.hex('#D97706'),
  spark: chalk.hex('#FCD34D'),
};

class UI {
  displayBanner() {
    const packageJson = require('../../../package.json');
    const version = packageJson.version;

    let logoLines;
    try {
      logoLines = figlet.textSync('SKF', { font: 'ANSI Shadow' }).trimEnd().split('\n');
      // Remove trailing empty lines from figlet output
      while (logoLines.length > 0 && !logoLines.at(-1).trim()) logoLines.pop();
    } catch {
      logoLines = ['  S K F'];
    }

    const w = 54;
    const frame = brand.dark;
    const top = frame('  ╔' + '═'.repeat(w) + '╗');
    const mid = frame('  ╟' + '─'.repeat(w) + '╢');
    const bottom = frame('  ╚' + '═'.repeat(w) + '╝');
    const row = (content) => {
      // eslint-disable-next-line no-control-regex -- stripping ANSI escape codes for visual width calculation
      const stripped = content.replaceAll(/\u001B\[\d+(?:;\d+)*m/g, '');
      const pad = Math.max(0, w - stripped.length - 2);
      return frame('  ║ ') + content + ' '.repeat(pad) + frame(' ║');
    };

    console.log();
    console.log(top);
    for (const line of logoLines) {
      console.log(row(brand.amber.bold(line.replace(/\s+$/, ''))));
    }
    console.log(mid);
    console.log(row(chalk.white.bold('Skill Forge') + chalk.dim(` v${version}`)));
    console.log(row(chalk.dim('Agent Skill Compiler') + ' '.repeat(15) + brand.spark('⚒')));
    console.log(mid);
    console.log(row(chalk.dim('Code · Docs · Discourse → Verified agent skills')));
    console.log(bottom);
    console.log();

    intro(brand.amber('Skill Forge Installer'));
  }

  async detectInstallation(projectDir) {
    const hasBmadSkf = await fs.pathExists(path.join(projectDir, SKF_FOLDER));
    const hasBmadDir = await fs.pathExists(path.join(projectDir, '_bmad'));

    if (hasBmadSkf) {
      return { type: 'existing', folder: SKF_FOLDER };
    }
    if (hasBmadDir) {
      return { type: 'bmad-ready', folder: SKF_FOLDER };
    }
    return { type: 'fresh', folder: SKF_FOLDER };
  }

  async promptInstall() {
    this.displayBanner();

    const projectDir = process.cwd();
    const defaultProjectName = path.basename(projectDir);
    const detection = await this.detectInstallation(projectDir);
    const skfFolder = detection.folder;

    log.info(`Target: ${brand.gold(projectDir)}`);

    let action = 'fresh';

    if (detection.type === 'existing') {
      const existingManifest = await readManifest(projectDir);
      const installedVersion = existingManifest?.version || null;
      const incomingVersion = require('../../../package.json').version;

      let versionLabel;
      let updateOptionLabel;
      if (!installedVersion) {
        versionLabel = `version unknown → v${incomingVersion}`;
        updateOptionLabel = `Update — Install v${incomingVersion}, keep config.yaml`;
      } else if (installedVersion === incomingVersion) {
        versionLabel = `v${installedVersion} — already at this version`;
        updateOptionLabel = `Update — Reinstall v${incomingVersion}, keep config.yaml`;
      } else if (compareVersions(installedVersion, incomingVersion)) {
        versionLabel = `v${installedVersion} → v${incomingVersion} available`;
        updateOptionLabel = `Update — Upgrade from v${installedVersion} to v${incomingVersion}, keep config.yaml`;
      } else {
        versionLabel = `v${installedVersion} → v${incomingVersion}, DOWNGRADE`;
        updateOptionLabel = `Update — Downgrade to v${incomingVersion}, keep config.yaml`;
      }

      log.warn(`Found existing installation at ${chalk.white(SKF_FOLDER + '/')} (${versionLabel})`);

      const choice = await select({
        message: 'What would you like to do?',
        options: [
          { label: updateOptionLabel, value: 'update' },
          { label: 'Fresh install — Remove everything and start over', value: 'fresh' },
          { label: 'Cancel', value: 'cancel' },
        ],
      });

      if (isCancel(choice) || choice === 'cancel') {
        cancel('Installation cancelled.');
        return { cancelled: true };
      }
      action = choice;
    } else {
      log.info(`Agents and workflows will be installed in ${chalk.white(skfFolder + '/')}`);
    }

    if (action === 'update') {
      log.info('Existing config.yaml will be preserved.');
      return {
        projectDir,
        skfFolder,
        _detection: detection,
        _action: action,
        cancelled: false,
      };
    }

    // Load saved config to pre-populate defaults on fresh reinstall
    const savedConfig = await this.loadSavedConfig(projectDir, skfFolder);
    if (savedConfig) {
      log.info('Previous configuration detected — defaults pre-populated.');
    }

    // Build IDE options from platform-codes.yaml
    const platforms = getAvailablePlatforms();
    const ideOptions = [
      ...platforms.map((p) => ({
        label: p.preferred ? `${p.label} (Recommended)` : p.label,
        value: p.value,
      })),
      { label: 'Other', value: 'other' },
    ];

    // Pre-check IDEs: saved config takes priority, then auto-detect from directories
    const savedIdes = savedConfig?.ides || [];
    let initialIdes = [];
    if (savedIdes.length > 0) {
      initialIdes = savedIdes;
    } else {
      const detectedIdes = await this.detectIdes(projectDir);
      if (detectedIdes.length > 0) {
        initialIdes = detectedIdes;
        log.info(`Auto-detected IDEs: ${brand.gold(detectedIdes.join(', '))}`);
      }
    }

    // Mark initially selected IDEs
    for (const opt of ideOptions) {
      opt.initialSelected = initialIdes.includes(opt.value);
    }

    // Project name
    const project_name = await text({
      message: 'Project name:',
      initialValue: savedConfig?.project_name || defaultProjectName,
    });
    if (isCancel(project_name)) {
      cancel('Installation cancelled.');
      return { cancelled: true };
    }

    // Skills output folder
    const skills_output_folder = await text({
      message: 'Where should generated skills be saved?',
      initialValue: savedConfig?.skills_output_folder || 'skills',
    });
    if (isCancel(skills_output_folder)) {
      cancel('Installation cancelled.');
      return { cancelled: true };
    }

    // Forge data folder
    const forge_data_folder = await text({
      message: 'Where should forge workspace artifacts be stored?',
      initialValue: savedConfig?.forge_data_folder || 'forge-data',
    });
    if (isCancel(forge_data_folder)) {
      cancel('Installation cancelled.');
      return { cancelled: true };
    }

    // IDE selection
    const ides = await multiselect({
      message: 'Which tools/IDEs are you using?',
      options: ideOptions,
      initialValues: initialIdes,
      required: true,
    });
    if (isCancel(ides)) {
      cancel('Installation cancelled.');
      return { cancelled: true };
    }

    // Learning material
    const install_learning = await confirm({
      message: 'Install learning & reference material?',
      initialValue: true,
    });
    if (isCancel(install_learning)) {
      cancel('Installation cancelled.');
      return { cancelled: true };
    }

    return {
      projectDir,
      project_name,
      skills_output_folder,
      forge_data_folder,
      ides,
      install_learning,
      skfFolder,
      _detection: detection,
      _action: action,
      cancelled: false,
    };
  }

  async detectIdes(projectDir) {
    const markers = getDetectionMarkers();
    const detected = [];
    for (const [ide, paths] of Object.entries(markers)) {
      for (const p of paths) {
        if (await fs.pathExists(path.join(projectDir, p))) {
          detected.push(ide);
          break;
        }
      }
    }
    return detected;
  }

  async loadSavedConfig(projectDir, skfFolder) {
    const configPath = path.join(projectDir, skfFolder, 'config.yaml');
    try {
      if (await fs.pathExists(configPath)) {
        const content = await fs.readFile(configPath, 'utf8');
        return yaml.load(content) || null;
      }
    } catch {
      // ignore parse errors
    }
    return null;
  }

  displaySuccess(skfFolder, ides = [], action = 'fresh') {
    // Build IDE name map from platform-codes.yaml
    const ideNames = { other: 'your IDE' };
    for (const p of getAvailablePlatforms()) {
      ideNames[p.value] = p.label;
    }

    let ideDisplay;
    if (!ides || ides.length === 0) {
      ideDisplay = 'your IDE';
    } else if (ides.length === 1) {
      ideDisplay = ideNames[ides[0]] || 'your IDE';
    } else {
      ideDisplay = ides.map((ide) => ideNames[ide] || ide).join(' or ');
    }

    let noteTitle;
    let noteBody;

    const activateCmd = brand.gold('@Ferris SF');

    if (action === 'update') {
      noteTitle = brand.amber.bold('Update complete!');
      noteBody = [
        `${chalk.white.bold('What Changed')}`,
        'SKF files and agents have been refreshed.',
        'Your config.yaml and sidecar state are preserved.',
        '',
        `${chalk.white.bold('Next Steps')}`,
        `1. Reload the agent in ${ideDisplay}:  ${activateCmd}`,
        '2. Run @Ferris SF to re-detect tools if needed',
      ].join('\n');
    } else {
      noteTitle = brand.amber.bold('Installation complete!');
      noteBody = [
        `${chalk.white.bold('Get Started')}`,
        `1. Open this folder in ${ideDisplay}`,
        `2. Activate Ferris:  ${activateCmd}`,
        '3. Ferris (your Skill Architect) will guide you through',
        '   setting up and forging your first agent skill',
      ].join('\n');
    }

    note(noteBody, noteTitle);

    outro(
      `${brand.spark('⚒')}  Agent: ${chalk.white('Ferris')} ${chalk.dim('(Skill Architect & Integrity Guardian)')}\n${brand.dark('⚡')} Docs: ${brand.amber('https://armelhbobdad.github.io/bmad-module-skill-forge')}`,
    );
  }
}

module.exports = { UI };

/**
 * SKF Status Command
 * Shows installation state, version, tier, configured IDEs, and sidecar status.
 */

const chalk = require('chalk');
const path = require('node:path');
const fs = require('fs-extra');
const yaml = require('js-yaml');
const { readManifest } = require('../lib/manifest');
const { getAvailablePlatforms } = require('../lib/ide-skills');

const SKF_FOLDER = '_bmad/skf';
const SIDECAR_FOLDER = '_bmad/_memory/forger-sidecar';

function getIdeNames() {
  const names = { other: 'Other' };
  for (const p of getAvailablePlatforms()) {
    names[p.value] = p.label;
  }
  return names;
}

async function readYaml(filePath) {
  try {
    const content = await fs.readFile(filePath, 'utf8');
    return yaml.load(content) || {};
  } catch {
    return null;
  }
}

async function getStatus(projectDir) {
  const skfDir = path.join(projectDir, SKF_FOLDER);
  const sidecarDir = path.join(projectDir, SIDECAR_FOLDER);

  const installed = await fs.pathExists(skfDir);
  if (!installed) {
    return { installed: false };
  }

  // Read config
  const config = await readYaml(path.join(skfDir, 'config.yaml'));

  // Read forge tier
  const forgeTier = await readYaml(path.join(sidecarDir, 'forge-tier.yaml'));

  // Read preferences
  const preferences = await readYaml(path.join(sidecarDir, 'preferences.yaml'));

  // Check agent skill in module dir (always present when installed)
  const agentInstalled = await fs.pathExists(path.join(skfDir, 'skf-forger', 'SKILL.md'));

  // Count workflow skills (skf-* directories with workflow.md)
  let workflowCount = 0;
  if (await fs.pathExists(skfDir)) {
    const entries = await fs.readdir(skfDir);
    for (const entry of entries) {
      if (!entry.startsWith('skf-')) continue;
      const wfPath = path.join(skfDir, entry, 'workflow.md');
      if (await fs.pathExists(wfPath)) {
        workflowCount++;
      }
    }
  }

  // Check output folders
  const skillsFolder = config?.skills_output_folder || 'skills';
  const forgeDataFolder = config?.forge_data_folder || 'forge-data';
  const skillsFolderExists = await fs.pathExists(path.join(projectDir, skillsFolder));
  const forgeDataFolderExists = await fs.pathExists(path.join(projectDir, forgeDataFolder));

  // Check sidecar state
  const sidecarExists = await fs.pathExists(sidecarDir);
  const tierDetected = forgeTier?.tier != null;

  // Read manifest
  const manifest = await readManifest(projectDir);

  return {
    installed: true,
    config,
    forgeTier,
    preferences,
    agentInstalled,
    workflowCount,
    skillsFolder,
    skillsFolderExists,
    forgeDataFolder,
    forgeDataFolderExists,
    sidecarExists,
    tierDetected,
    manifest,
  };
}

function displayStatus(status, version) {
  console.log('');
  console.log(chalk.hex('#F59E0B').bold('  Skill Forge — Status'));
  console.log(chalk.dim(`  v${version}`));
  console.log('');

  if (!status.installed) {
    console.log(chalk.yellow('  Not installed.'));
    console.log(chalk.dim('  Run: npx bmad-module-skill-forge install'));
    console.log('');
    return;
  }

  const config = status.config || {};

  // Installation
  const manifest = status.manifest;
  console.log(chalk.white.bold('  Installation'));
  console.log(`    Project:      ${chalk.hex('#FBBF24')(config.project_name || '(unknown)')}`);
  console.log(`    SKF folder:   ${chalk.dim(SKF_FOLDER + '/')}`);
  console.log(`    Agent:        ${status.agentInstalled ? chalk.green('installed') : chalk.yellow('not installed')}`);
  console.log(`    Workflows:    ${chalk.white(status.workflowCount)}`);
  if (manifest) {
    console.log(
      `    Installed:    ${chalk.dim(manifest.installed_at ? new Date(manifest.installed_at).toLocaleDateString() : '(unknown)')}`,
    );
    console.log(`    Manifest:     ${chalk.green('present')}`);
  } else {
    console.log(`    Manifest:     ${chalk.yellow('missing')} ${chalk.dim('(reinstall to generate)')}`);
  }
  console.log('');

  // IDEs
  const ides = config.ides || [];
  const ideNames = getIdeNames();
  console.log(chalk.white.bold('  IDEs'));
  if (ides.length > 0) {
    for (const ide of ides) {
      console.log(`    ${chalk.green('●')} ${ideNames[ide] || ide}`);
    }
  } else {
    console.log(chalk.dim('    None configured'));
  }
  console.log('');

  // Forge Tier
  const ft = status.forgeTier || {};
  const tools = ft.tools || {};
  console.log(chalk.white.bold('  Forge Tier'));
  if (status.tierDetected) {
    const tierColors = { Quick: chalk.yellow, Forge: chalk.hex('#F59E0B'), 'Forge+': chalk.hex('#E88D0E'), Deep: chalk.hex('#FCD34D') };
    const tierColor = tierColors[ft.tier] || chalk.white;
    console.log(`    Tier:         ${tierColor(ft.tier)}`);
    console.log(`    Detected:     ${chalk.dim(ft.tier_detected_at || '(unknown)')}`);
  } else {
    console.log(chalk.dim('    Not detected yet — run @Ferris SF'));
  }
  console.log(`    ast-grep:     ${formatTool(tools.ast_grep)}`);
  console.log(`    gh CLI:       ${formatTool(tools.gh_cli)}`);
  console.log(`    ccc:          ${formatTool(tools.ccc)}`);
  console.log(`    QMD:          ${formatTool(tools.qmd)}`);
  console.log('');

  // Output Folders
  console.log(chalk.white.bold('  Output Folders'));
  console.log(`    Skills:       ${status.skillsFolder}/ ${status.skillsFolderExists ? chalk.green('✓') : chalk.yellow('missing')}`);
  console.log(`    Forge data:   ${status.forgeDataFolder}/ ${status.forgeDataFolderExists ? chalk.green('✓') : chalk.yellow('missing')}`);
  console.log('');

  // Sidecar
  console.log(chalk.white.bold('  Sidecar'));
  console.log(`    State:        ${status.sidecarExists ? chalk.green('initialized') : chalk.yellow('missing')}`);
  console.log(`    Location:     ${chalk.dim(SIDECAR_FOLDER + '/')}`);
  console.log('');
}

function formatTool(value) {
  if (value === true || value === 'available') return chalk.green('available');
  if (value == null) return chalk.dim('not detected');
  return chalk.yellow(String(value));
}

module.exports = {
  command: 'status',
  description: 'Show SKF installation state, version, tier, and configuration',
  options: [],
  action: async () => {
    try {
      const projectDir = process.cwd();
      const packageJson = require('../../../package.json');
      const status = await getStatus(projectDir);
      displayStatus(status, packageJson.version);
    } catch (error) {
      console.error(chalk.red('\nFailed to read status:'), error.message);
      process.exit(1);
    }
  },
};

